"""Pure helpers shared by `Client`, `Agent`, `Cursor`, and their async mirrors.

This module deliberately depends on nothing from `_client`, `_agent`,
`_run`, or `_cursor` so it can sit at the bottom of the import graph
and break what would otherwise be a four-way cycle. Anything stateful
(default-client lifecycle, transport construction) lives in `_client`.
"""

from __future__ import annotations

import os
import uuid
from typing import Any, Mapping

from .errors import ConfigurationError
from .types import (
    AgentOptions,
    CloudAgentOptions,
    JsonObject,
    LocalAgentOptions,
    ModelSelection,
    SendOptions,
    options_to_json,
)

AGENT_SERVICE = "sdk.v1.SdkAgentService"
BRIDGE_CONTROL_SERVICE = "sdk.v1.SdkBridgeControlService"
CURSOR_SERVICE = "sdk.v1.SdkCursorService"

# `_list_options` accepts named keyword args (preferred) and also tolerates raw
# `options=` dicts that use snake_case. Names listed here get folded into the
# canonical camelCase wire shape so both spellings end up identical on the wire.
_LIST_OPTION_SNAKE_TO_CAMEL = {
    "include_archived": "includeArchived",
    "pr_url": "prUrl",
    "api_key": "apiKey",
}

_RUNTIME_OPTION_ALIASES = {
    "auto": "RUNTIME_AUTO",
    "local": "RUNTIME_LOCAL",
    "cloud": "RUNTIME_CLOUD",
}


def _api_key_or_env(api_key: str | None = None, *, allow_env: bool = True) -> str:
    if api_key:
        return api_key
    return os.environ.get("CURSOR_API_KEY", "") if allow_env else ""


def _normalize_runtime_option(runtime: Any) -> Any:
    if isinstance(runtime, str):
        return _RUNTIME_OPTION_ALIASES.get(runtime, runtime)
    return runtime


def _normalize_runtime_options(options: Mapping[str, Any] | None) -> dict[str, Any]:
    normalized = dict(options or {})
    if "runtime" in normalized:
        normalized["runtime"] = _normalize_runtime_option(normalized["runtime"])
    return normalized


def _is_cloud_agent_rpc(method: str, message: Mapping[str, Any]) -> bool:
    options = message.get("options")
    option_mapping = options if isinstance(options, Mapping) else {}
    agent_id = str(message.get("agentId") or "")
    if method == "CreateAgent":
        return bool(option_mapping.get("cloud"))
    if method == "ResumeAgent":
        return agent_id.startswith("bc-") or bool(option_mapping.get("cloud"))
    if method in {
        "GetAgent",
        "ArchiveAgent",
        "UnarchiveAgent",
        "DeleteAgent",
        "ListAgentMessages",
        "ListArtifacts",
        "DownloadArtifact",
    }:
        return agent_id.startswith("bc-")
    if method in {"ListAgents", "ListRuns", "GetRun"}:
        return option_mapping.get("runtime") in {"cloud", "RUNTIME_CLOUD"}
    if method == "Send":
        return agent_id.startswith("bc-")
    if method in {"CancelRun", "WaitLiveRun", "ObserveRun", "GetRunConversation"}:
        # Run-scoped RPCs identify the run only by runId, not agentId, so we
        # can't tell from the request shape whether the underlying run is
        # cloud-hosted. Treat them as cloud-routed unconditionally on remote
        # bridges so a malicious caller-supplied bridge consumer can't read
        # or cancel another user's cloud run by guessing/leaking its runId.
        # Local clients have _allow_api_key_env_fallback=True and short-circuit
        # the guard before this classifier is consulted.
        return True
    return False


def _options_with_api_key(
    api_key: str | None, options: Mapping[str, Any] | None = None
) -> dict[str, Any]:
    """Merge an Agent's stored api_key into an options dict.

    Cloud-routed Agent RPCs accept an `apiKey` field on the wire that the
    server uses to validate the caller. If the Agent has a stored api_key
    and the options didn't already include one, propagate it so callers
    don't have to thread it through every method. Returns a fresh dict so
    callers can mutate it freely. Shared between sync `Agent` and async
    `AsyncAgent` so the propagation rule has one source of truth.
    """
    merged: dict[str, Any] = dict(options or {})
    if api_key and not merged.get("apiKey"):
        merged["apiKey"] = api_key
    return merged


def _require_send_api_key_for_remote_cloud_agent(
    *, allow_env_fallback: bool, agent_id: str, api_key: str | None
) -> None:
    """Cloud-routed Send RPCs through a caller-supplied bridge require an
    explicit api_key on the agent. Local clients short-circuit via the
    env-fallback flag. Shared between sync `Agent.send` and async
    `AsyncAgent.send` so the security predicate has one source of truth.
    """
    if not allow_env_fallback and agent_id.startswith("bc-") and not api_key:
        raise ConfigurationError(
            "Cloud agent send through a caller-supplied bridge requires "
            "an agent created or resumed with an explicit api_key",
            code="missing_api_key",
        )


def _resolve_create_agent_options(
    options: AgentOptions | Mapping[str, Any] | None,
    *,
    model: str | ModelSelection | Mapping[str, Any] | None,
    api_key: str | None,
    name: str | None,
    local: LocalAgentOptions | Mapping[str, Any] | None,
    cloud: CloudAgentOptions | Mapping[str, Any] | None,
    allow_env_fallback: bool,
) -> JsonObject:
    """Build and validate the wire `options` dict for `CreateAgent`."""
    request_options = options_to_json(
        options, model=model, api_key=api_key, name=name, local=local, cloud=cloud
    )

    resolved_api_key = _api_key_or_env(
        request_options.get("apiKey") or api_key,
        allow_env=allow_env_fallback,
    )
    if not resolved_api_key:
        raise ConfigurationError(
            "Agent.create requires api_key (set CURSOR_API_KEY or pass "
            "api_key=...; for remote bridges set allow_api_key_env_fallback=True "
            "to opt in to env-var fallback).",
            code="missing_api_key",
        )
    request_options["apiKey"] = resolved_api_key

    if not request_options.get("model"):
        raise ConfigurationError(
            'Agent.create requires model (e.g. model="composer-2" or '
            "model=ModelSelection(id=...)).",
            code="missing_model",
        )
    return request_options


def _create_agent_idempotency_key(
    request_options: Mapping[str, Any], explicit_idempotency_key: str | None
) -> str:
    """Return the CreateAgent idempotency key to send on the bridge wire.

    The bridge only supports CreateAgent idempotency for cloud agents. Local
    agents use the local runtime store instead, and sending a non-empty key
    makes the bridge reject the request as unimplemented.
    """
    if request_options.get("cloud"):
        return explicit_idempotency_key or str(uuid.uuid4())
    if explicit_idempotency_key:
        raise ConfigurationError(
            "Agent.create idempotency_key is only supported for cloud agents.",
            code="local_idempotency_key_unsupported",
        )
    return ""


def _list_options(
    options: Mapping[str, Any] | None = None,
    *,
    runtime: str | None = None,
    cwd: str | os.PathLike[str] | None = None,
    include_archived: bool | None = None,
    pr_url: str | None = None,
    limit: int | None = None,
    api_key: str | None = None,
) -> dict[str, Any]:
    """Build the wire `options` dict for List* RPCs.

    Named kwargs take precedence; if the caller passed a raw `options` dict
    that already contains snake_case keys, fold them into the canonical
    camelCase shape so callers can mix and match without surprise.
    """
    merged = dict(options or {})
    if runtime is not None:
        merged["runtime"] = runtime
    if cwd is not None:
        merged["cwd"] = os.fspath(cwd)
    if include_archived is not None:
        merged["includeArchived"] = include_archived
    if pr_url is not None:
        merged["prUrl"] = pr_url
    if limit is not None:
        merged["limit"] = limit
    if api_key is not None:
        merged["apiKey"] = api_key
    for snake, camel in _LIST_OPTION_SNAKE_TO_CAMEL.items():
        if snake in merged:
            merged.setdefault(camel, merged[snake])
            del merged[snake]
    if "runtime" in merged:
        merged["runtime"] = _normalize_runtime_option(merged["runtime"])
    return merged


def _model_override_from_send_options(
    options: SendOptions | Mapping[str, Any] | None,
) -> dict[str, Any] | None:
    if isinstance(options, SendOptions):
        if not options.model:
            return None
        return ModelSelection.from_value(options.model).to_json()
    if isinstance(options, Mapping):
        model = options.get("model")
        if model:
            return ModelSelection.from_value(model).to_json()
    return None
